                    bgColor="#EFF6FF"
                />
                <PillarCard
                    icon={Moon}
                    title="2. Estilo de Vida"
                    desc="Sue├▒o, estr├⌐s y tiempo"
                    delay={0.3}
                    color="#6366F1"
                    bgColor="#EEF2FF"
                />
                <PillarCard
                    icon={Heart}
                    title="3. Preferencias"
                    desc="Gustos y salud"
                    delay={0.4}
                    color="#EC4899"
                    bgColor="#FDF2F8"
                />
                <PillarCard
