                <div style={{ textAlign: 'right', display: 'flex', alignItems: 'baseline', gap: '4px' }}>
                    <span style={{ fontSize: large ? '1.35rem' : '1.15rem', fontWeight: 800, color: '#0F172A', letterSpacing: '-0.02em' }}>
