    const checkPlanLimit = useCallback(async (specificUserId = null) => {
        try {
            const userId = specificUserId || session?.user?.id || localStorage.getItem('mealfit_user_id');

            if (!userId || userId === 'guest') {
                setPlanCount(0);
                return 0;
            }

            const response = await fetchWithAuth(`/api/user/credits/${userId}`);
            if (!response.ok) {
                const errorText = await response.text();
                throw new Error(`Error consultando cr├⌐ditos: ${response.status} - ${errorText}`);
            }
            const data = await response.json();

            setPlanCount(data.credits || 0);
            return data.credits || 0;
        } catch (error) {
            console.error("Error verificando l├¡mites de API:", error);
            return 0;
        }
    }, [session]);

    // --- 2. MANEJO DE SESI├ôN Y PERFIL (SUPABASE) ---
    const fetchProfile = useCallback(async (userId) => {
        try {
            const { data } = await supabase
                .from('user_profiles')
                .select('*')
                .eq('id', userId)
                .single();

            if (data) {
                setUserProfile(data);
                // Sincronizar UI form data con health_profile (si existe y tiene datos)
                if (data.health_profile && Object.keys(data.health_profile).length > 0) {
                    setFormData(prev => ({
                        ...prev,
                        ...data.health_profile
                    }));
                }
            }
        } catch (error) {
            console.error('Error cargando perfil:', error);
        }
    }, [setFormData, setUserProfile]);

    const refreshProfileAndPlan = useCallback(async () => {
        const userId = session?.user?.id || localStorage.getItem('mealfit_user_id');
        if (userId) {
            try {
                const { data } = await supabase
                    .from('user_profiles')
                    .select('*')
                    .eq('id', userId)
                    .single();

                if (data) {
                    setUserProfile(data);
                    
                    let latestFormData = { ...formData };
                    if (data.health_profile && Object.keys(data.health_profile).length > 0) {
                        setFormData(prev => {
                            latestFormData = { ...prev, ...data.health_profile };
                            return latestFormData;
                        });
                        
                        // toast.info("Actualizando tu plan basado en tus nuevos datos...", { duration: 4000 });
                        // 
                        // // Generar nuevo plan con los datos sincronizados
                        // const newPlan = await generateAIPlan(latestFormData);
                        // if (newPlan) {
                        //     setPlanData(newPlan);
                        //     localStorage.setItem('mealfit_plan', JSON.stringify(newPlan));
                        //     await savePlanToHistory(newPlan);
                        //     toast.success("┬íPlan sincronizado exitosamente!");
                        // }
                    }
                }
            } catch (error) {
                console.error("Error refreshing profile or plan:", error);
            }
        }
    }, [session, formData]);

    useEffect(() => {
        const handleAuthChange = async (currentSession) => {
            // Evitar actualizaciones innecesarias si la sesi├│n es id├⌐ntica
            // Usamos JSON.stringify para comparar objetos de forma segura
            if (session?.user?.id && currentSession?.user?.id && session.user.id === currentSession.user.id) {
                return;
            }

            setSession(currentSession);

            if (currentSession?.user) {
                const userId = currentSession.user.id;
                localStorage.setItem('mealfit_user_id', userId);

                const lastOwner = localStorage.getItem('mealfit_last_form_owner');
                if (lastOwner && lastOwner !== 'guest' && lastOwner !== userId) {
                    // Los datos pertenecen a un usuario diferente, por lo que limpiamos para el usuario nuevo/diferente
                    localStorage.removeItem('mealfit_form');
                    setFormData(initialFormData);
                }
                localStorage.setItem('mealfit_last_form_owner', userId);

                // Ejecutamos todo en paralelo
                await Promise.all([
                    fetchProfile(userId),
                    checkPlanLimit(userId),
                    restoreSessionData(userId)
                ]);
            } else {
                // Logout / No sesi├│n
                setUserProfile(null);
                setPlanCount(0);
                setPlanData(null);
                localStorage.removeItem('mealfit_user_id');
                localStorage.removeItem('mealfit_plan');
                localStorage.removeItem('mealfit_guest_session');
                // Al cerrar sesi├│n NO limpiamos mealfit_form para que un guest pueda seguir us├índolo
                setLoadingData(false);
            }
            setLoadingAuth(false);
            
            // ≡ƒÜÇ Desvanecer Splash Screen nativo una vez React est├⌐ listo con la sesi├│n
            setTimeout(() => {
                const splash = document.getElementById('pwa-splash');
                if (splash) {
                    splash.style.opacity = '0';
                    setTimeout(() => splash.remove(), 500);
                }
            }, 100); // Darle un mini-delay para que React pinte el ProtectedRoute o Dashboard
        };

        // Obtener sesi├│n inicial
        supabase.auth.getSession().then(({ data: { session: initialSession } }) => {
            handleAuthChange(initialSession);
        });

        // Escuchar cambios en tiempo real
        const {
            data: { subscription },
        } = supabase.auth.onAuthStateChange((_event, newSession) => {
            handleAuthChange(newSession);
        });

        return () => subscription.unsubscribe();

        // Agregamos 'session' a las dependencias para cumplir con el Linter
        // La l├│gica dentro de handleAuthChange previene bucles infinitos
    }, [checkPlanLimit, restoreSessionData, session]);

    // --- ESCUCHA DE SUPABASE REALTIME (Actualizaciones de la IA) ---
    useEffect(() => {
        const userId = session?.user?.id;
        if (!userId) return;


        
        const profileSubscription = supabase
            .channel('public:user_profiles')
            .on(
                'postgres_changes',
                {
                    event: 'UPDATE',
                    schema: 'public',
                    table: 'user_profiles',
                    filter: `id=eq.${userId}`
                },
                (payload) => {

                    // Disparar sincronizaci├│n m├ígica
                    refreshProfileAndPlan();
                }
            )
            .subscribe();

        return () => {

            supabase.removeChannel(profileSubscription);
        };
    }, [session, refreshProfileAndPlan]);

    // --- FUNCI├ôN PARA ACTUALIZAR PERFIL EN DB ---
    const updateUserProfile = async (updates) => {
        try {
            if (!session?.user) throw new Error('No hay sesi├│n activa');

            const { error } = await supabase
                .from('user_profiles')
                .update(updates)
                .eq('id', session.user.id);

            if (error) throw error;

            setUserProfile((prev) => ({ ...prev, ...updates }));
            return { success: true };
        } catch (error) {
            console.error('Error actualizando perfil:', error);
            return { success: false, error };
        }
    };

    // --- EFECTOS DE PERSISTENCIA LOCAL ---
    useEffect(() => {
        if (formData) localStorage.setItem('mealfit_form', JSON.stringify(formData));
    }, [formData]);

    useEffect(() => {
        if (planData) localStorage.setItem('mealfit_plan', JSON.stringify(planData));
    }, [planData]);

    useEffect(() => {
        if (likedMeals) localStorage.setItem('mealfit_likes', JSON.stringify(likedMeals));
    }, [likedMeals]);

    useEffect(() => {
        if (dislikedMeals) localStorage.setItem('mealfit_dislikes', JSON.stringify(dislikedMeals));
    }, [dislikedMeals]);


    // --- L├ôGICA DE NEGOCIO Y WEBHOOKS ---

    const toggleMealLike = async (mealName, mealType) => {
        const isCurrentlyLiked = !!likedMeals[mealName];

        setLikedMeals(prev => ({
            ...prev,
            [mealName]: !isCurrentlyLiked
        }));

        if (isCurrentlyLiked) return;

        try {
            const userId = session?.user?.id || localStorage.getItem('mealfit_user_id');

            if (!userId) {
                toast.error("Inicia sesi├│n para guardar tus favoritos");
                setLikedMeals(prev => {
                    const newState = { ...prev };
                    delete newState[mealName];
                    return newState;
                });
                return;
            }

            const API_URL = '/api/like';

            const response = await fetchWithAuth(API_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    user_id: userId,
                    meal_name: mealName,
                    meal_type: mealType
                })
            });

            if (!response.ok) {
                throw new Error(`El Agente IA respondi├│ con error: ${response.status}`);
            }

        } catch (error) {
            console.error("Γ¥î ERROR AL ENVIAR LIKE:", error);
            setLikedMeals(prev => {
                const newState = { ...prev };
                delete newState[mealName];
                return newState;
            });
        }
    };

    // --- REGENERACI├ôN INTELIGENTE CON PERSISTENCIA DE DB ---
    const regenerateSingleMeal = async (dayIndex, mealIndex, mealType, currentName) => {
        const planDays = planData.days || [{ day: 1, meals: planData.meals || planData.perfectDay || [] }];
        const currentMeals = planDays[dayIndex]?.meals || [];
        const targetCalories = currentMeals[mealIndex]?.cals || 400;
        const userDietType = formData.dietType || "balanced";
        const userId = session?.user?.id || localStorage.getItem('mealfit_user_id');



        try {
            // 1. LLAMADA A LA IA
            const API_SWAP_URL = '/api/swap-meal';
            const sessionId = localStorage.getItem('mealfit_user_id') || 'guest_session';
            const response = await fetchWithAuth(API_SWAP_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    user_id: userId || "guest",
                    session_id: sessionId,
                    rejected_meal: currentName,
                    meal_type: mealType,
                    target_calories: targetCalories,
                    diet_type: userDietType,
                    allergies: formData.allergies || [],
                    dislikes: formData.dislikes || [],
                    liked_meals: Object.keys(likedMeals || {}),
                    disliked_meals: Object.keys(dislikedMeals || {})
                })
            });

            if (!response.ok) throw new Error("Error conectando con la IA");

            const newMealData = await response.json();


            // 2. ACTUALIZAR ESTADO LOCAL
            const updatedPlan = { ...planData };
            
            // Retrocompatibilidad r├ípida al regenerar
            if (!updatedPlan.days) {
                 updatedPlan.days = [{ day: 1, meals: updatedPlan.meals || updatedPlan.perfectDay || [] }];
                 delete updatedPlan.meals;
                 delete updatedPlan.perfectDay;
            }

            const updatedDays = [...updatedPlan.days];
            const updatedDayObj = { ...updatedDays[dayIndex] };
            const updatedMeals = [...updatedDayObj.meals];

            updatedMeals[mealIndex] = {
                ...updatedMeals[mealIndex],
                name: newMealData.name,
                desc: newMealData.desc,
                cals: newMealData.cals,
                prep_time: newMealData.prep_time,
                recipe: newMealData.recipe || [],
                ingredients: newMealData.ingredients || []
            };

            updatedDayObj.meals = updatedMeals;
            updatedDays[dayIndex] = updatedDayObj;
            updatedPlan.days = updatedDays;

            // Add rejected meal to disliked list with current timestamp
            setDislikedMeals(prev => ({
                ...prev,
                [currentName]: Date.now()
            }));

            // Actualizamos UI inmediatamente
            setPlanData(updatedPlan);
            localStorage.setItem('mealfit_plan', JSON.stringify(updatedPlan));

            // 3. PERSISTENCIA EN SUPABASE (CR├ìTICO)
            if (userId && userId !== 'guest') {
                try {
                    // a) Obtener el ID del plan actual (el m├ís reciente)
                    const { data: latestRows } = await supabase
                        .from('meal_plans')
                        .select('id')
                        .eq('user_id', userId)
                        .order('created_at', { ascending: false })
                        .limit(1);

                    if (latestRows && latestRows.length > 0) {
                        const planId = latestRows[0].id;


                        // b) Ejecutar UPDATE del campo plan_data
                        const { error: updateError } = await supabase
                            .from('meal_plans')
                            .update({ plan_data: updatedPlan }) // Guardamos el JSON modificado
                            .eq('id', planId);

                        if (updateError) {
                            console.error("Γ¥î Error Supabase UPDATE:", updateError);
                            toast.error("Error de sincronizaci├│n", { description: "El cambio es solo local." });
                        } else {

                        }
                    }
                } catch (dbError) {
                    console.error("Γ¥î Fallo cr├¡tico DB:", dbError);
                }
            }

            // Actualizar cr├⌐ditos en tiempo real despu├⌐s de regenerar exitosamente
            setTimeout(async () => {
                await checkPlanLimit();
            }, 1000);

            return newMealData.name;

        } catch (error) {
            // CORRECCI├ôN DEL ERROR DE LINTER: Usamos la variable 'error'
            console.error("Γ¥î Fall├│ IA, usando fallback local...", error);

            // Fallback Local
            const localFallback = getAlternativeMeal(mealType, currentName, targetCalories, userDietType);

            const updatedPlan = { ...planData };
            if (!updatedPlan.days) {
                 updatedPlan.days = [{ day: 1, meals: updatedPlan.meals || updatedPlan.perfectDay || [] }];
                 delete updatedPlan.meals;
                 delete updatedPlan.perfectDay;
            }

            const updatedDays = [...updatedPlan.days];
            const updatedDayObj = { ...updatedDays[dayIndex] };
            const updatedMeals = [...updatedDayObj.meals];

            updatedMeals[mealIndex] = {
                ...updatedMeals[mealIndex],
                name: localFallback.name,
                desc: localFallback.desc,
                cals: localFallback.cals,
                recipe: localFallback.recipe
            };
            
            updatedDayObj.meals = updatedMeals;
            updatedDays[dayIndex] = updatedDayObj;
            updatedPlan.days = updatedDays;

            setPlanData(updatedPlan);
            return localFallback.name;
        }
    };

    const updateData = (field, value) => {
        setFormData((prev) => ({ ...prev, [field]: value }));
        localStorage.setItem('mealfit_last_form_owner', session?.user?.id || 'guest');
    };

    const saveGeneratedPlan = async (data) => {
        setPlanData(data);
        setLikedMeals({});
        
        // NOTA: NO guardamos en Supabase aqu├¡.
        // El backend ya lo hace en _save_plan_and_track_background() con datos m├ís completos
        // (meal_names, ingredients, techniques, frequency tracking).
        // Guardarlo aqu├¡ tambi├⌐n causaba duplicados en el historial.

        setTimeout(async () => {
            await checkPlanLimit();
        }, 2000);
    };

    const restorePlan = async (pastPlanData) => {
        if (!pastPlanData) return;

        // 1. Actualizar estado local inmediatamente
        setPlanData(pastPlanData);
        setLikedMeals({});
        localStorage.setItem('mealfit_plan', JSON.stringify(pastPlanData));
        localStorage.setItem('mealfit_likes', JSON.stringify({}));

        // 2. Sincronizar con Supabase para que cloud sync no lo revierta
        const userId = session?.user?.id || localStorage.getItem('mealfit_user_id');
        if (userId && userId !== 'guest') {
            try {
                // Obtener el plan m├ís reciente del usuario
                const { data: latestRows } = await supabase
                    .from('meal_plans')
                    .select('id')
                    .eq('user_id', userId)
                    .order('created_at', { ascending: false })
                    .limit(1);

                if (latestRows && latestRows.length > 0) {
                    const planId = latestRows[0].id;

                    // Actualizar el plan_data del registro m├ís reciente
                    const { error: updateError } = await supabase
                        .from('meal_plans')
                        .update({ plan_data: pastPlanData })
                        .eq('id', planId);

                    if (updateError) {
                        console.error('Γ¥î Error sincronizando plan restaurado:', updateError);
                        toast.warning('Plan restaurado localmente', {
                            description: 'No se pudo sincronizar con la nube.'
                        });
                    } else {

                    }
                }
            } catch (dbError) {
                console.error('Γ¥î Error de DB al restaurar plan:', dbError);
            }
        }
    };

    const nextStep = () => { setDirection(1); setCurrentStep((prev) => prev + 1); };
    const prevStep = () => { setDirection(-1); setCurrentStep((prev) => Math.max(0, prev - 1)); };

    const resetApp = async () => {
        // NO limpiamos mealfit_form para que tras cerrar sesi├│n, 
        // los datos sigan presentes para invitados, pero s├¡ se limpiar├ín al entrar con otra cuenta.
        localStorage.removeItem('mealfit_plan');
        localStorage.removeItem('mealfit_likes');
        localStorage.removeItem('mealfit_user_id');
        localStorage.removeItem('mealfit_guest_session');
        localStorage.removeItem('mealfit_guest_sessions_list');
        localStorage.removeItem('mealfit_current_session');
        localStorage.removeItem('mealfit_dislikes');

        await supabase.auth.signOut();

        setPlanData(null);
        setLikedMeals({});
        setDislikedMeals({});
        setUserProfile(null);
        setPlanCount(0);
        setCurrentStep(0);
        setLoadingData(false);
    };

    const upgradeUserPlan = async (tier = 'plus', subscriptionId = null) => {
        try {
            const userId = session?.user?.id || localStorage.getItem('mealfit_user_id');
            if (!userId) throw new Error("No user ID");


            if (subscriptionId) {
                // Validaci├│n Segura B2B con nuestro Backend
                toast.loading('Verificando tu pago. Por favor espera...', { id: 'payment-verify' });
                const response = await fetchWithAuth('/api/subscription/verify', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        user_id: userId,
                        subscriptionID: subscriptionId,
                        tier: tier
                    })
                });

                if (!response.ok) {
                    const errData = await response.json();
                    throw new Error(errData.detail || "Fallo en la verificaci├│n del pago en el servidor.");
                }
                
                toast.success('Pago verificado exitosamente.', { id: 'payment-verify' });
                
                // Recargar el perfil desde la base de datos ya que el servidor hizo el UPDATE
                await refreshProfileAndPlan();
                
            } else {
                // Caso antiguo o admin bypass
                console.warn("ΓÜá∩╕Å Bypass de suscripci├│n llamado (Sin ID de suscripci├│n).");
                const { error } = await supabase
                    .from('user_profiles')
                    .update({
                        plan_tier: tier,
                        updated_at: new Date()
                    })
                    .eq('id', userId);
                if (error) throw error;
                setUserProfile(prev => ({ ...prev, plan_tier: tier }));
            }

            await checkPlanLimit(userId);
            
            const planNames = { basic: 'Mealfit B├ísico', plus: 'Mealfit Plus', ultra: 'Mealfit Ultra Ilimitado' };
            const planName = planNames[tier] || 'Mealfit Plus';
            
            toast.success(`┬íBienvenido a ${planName}!`, {
                description: 'Has desbloqueado acceso premium.',
                duration: 5000,
                icon: '≡ƒîƒ'
            });
            return true;
        } catch (error) {
            console.error("Error upgrading user:", error);
            toast.error(error.message || 'Error al actualizar perfil');
            toast.dismiss('payment-verify');
            return false;
        }
    };

    const isPlus = ['basic', 'plus', 'admin', 'ultra'].includes(userProfile?.plan_tier);

    let userPlanLimit = PLAN_LIMIT;
    if (userProfile?.plan_tier === 'basic') userPlanLimit = 50;
    else if (userProfile?.plan_tier === 'plus') userPlanLimit = 200;
    else if (['ultra', 'admin'].includes(userProfile?.plan_tier)) userPlanLimit = 'Ilimitado';

    return (
        <AssessmentContext.Provider value={{
            session,
            loadingAuth,
            loadingData,
            userProfile,
            updateUserProfile,
            currentStep,
            setCurrentStep,
            direction,
            nextStep,
            prevStep,
            formData,
            updateData,
            planData,
            saveGeneratedPlan,
            likedMeals,
            toggleMealLike,
            dislikedMeals,
            regenerateSingleMeal,
            resetApp,
            planCount,
            PLAN_LIMIT,
            userPlanLimit,
            checkPlanLimit,
            isPlus,
            remainingCredits: typeof userPlanLimit === 'number' ? Math.max(0, userPlanLimit - planCount) : 'Γê₧',
            upgradeUserPlan,
            restorePlan,
            refreshProfileAndPlan
        }}>
            {children}
        </AssessmentContext.Provider>
    );
};

AssessmentProvider.propTypes = { children: PropTypes.node.isRequired };

// eslint-disable-next-line react-refresh/only-export-components
export const useAssessment = () => useContext(AssessmentContext);

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAssessment } from '../context/AssessmentContext';
import { Send, Bot, Loader2, Paperclip, X, Image as ImageIcon, Plus, MessageSquare, History, Menu, Apple, Dumbbell, Utensils, Camera, Sparkles, Lock, Trash2, Check, Mic, ArrowUp, Square, ThumbsUp, ThumbsDown, RefreshCw, Copy, MoreVertical, LayoutDashboard, ShoppingBag, Clock, Settings, Edit2, Ghost } from 'lucide-react';
import DashboardLayout from '../components/dashboard/DashboardLayout';
import { fetchWithAuth } from '../config/api';
import ReactMarkdown from 'react-markdown';
import { MemoizedMessageBubble } from '../components/agent/MessageBubble';
import { SidebarRecientes } from '../components/agent/SidebarRecientes';


const AgentPage = () => {
    const { session, planData, formData, updateData, saveGeneratedPlan, userProfile, isPlus, checkPlanLimit } = useAssessment();
    const navigate = useNavigate();
    const [titlePollCount, setTitlePollCount] = useState(0);
    const [showNavMenu, setShowNavMenu] = useState(false);
    const navMenuRef = useRef(null);

    // IsMobile detection para asegurar sobrescritura inline a prueba de fallos de iOS
    const [isMobile, setIsMobile] = useState(typeof window !== 'undefined' ? window.innerWidth <= 1024 : false);

    useEffect(() => {
        const handleResize = () => setIsMobile(window.innerWidth <= 1024);
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    // Close nav menu on outside click
    useEffect(() => {
        const handleClickOutside = (e) => {
            if (navMenuRef.current && !navMenuRef.current.contains(e.target)) {
                setShowNavMenu(false);
            }
        };
        if (showNavMenu) document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [showNavMenu]);
    
    const [localSessionId, setLocalSessionId] = useState(() => {
        const saved = localStorage.getItem('mealfit_guest_session');
        if (saved) return saved;
        const newId = crypto.randomUUID();
        localStorage.setItem('mealfit_guest_session', newId);
        return newId;
    });

    const [guestSessionIds, setGuestSessionIds] = useState(() => {
        const savedList = localStorage.getItem('mealfit_guest_sessions_list');
        if (savedList) {
            let list = JSON.parse(savedList);
            if (!list.includes(localSessionId)) {
                list.unshift(localSessionId);
                list = list.slice(0, 40);
                localStorage.setItem('mealfit_guest_sessions_list', JSON.stringify(list));
            }
            return list;
        }
        const initialList = [localSessionId];
        localStorage.setItem('mealfit_guest_sessions_list', JSON.stringify(initialList));
        return initialList;
    });
    
    const [currentSessionId, _setCurrentSessionId] = useState(() => {
        return localStorage.getItem('mealfit_current_session') || localSessionId;
    });
    const setCurrentSessionId = (id) => {
        localStorage.setItem('mealfit_current_session', id);
        _setCurrentSessionId(id);
    };
    
    // Escuchar el logout para limpiar el estado interno
    useEffect(() => {
        if (!session?.user?.id && !userProfile?.id) {
            const currentGuestSession = localStorage.getItem('mealfit_guest_session');
            if (!currentGuestSession) {
                const newId = crypto.randomUUID();
                localStorage.setItem('mealfit_guest_session', newId);
                setLocalSessionId(newId);
                setCurrentSessionId(newId);
                setMessages([]);
                setChatSessions([]);
            }
        } else if (session?.user?.id || userProfile?.id) {
            const userId = session?.user?.id || userProfile?.id;
            const initUserSession = async () => {
                try {
                    const response = await fetchWithAuth(`/api/chat/sessions/${userId}`);
                    if (response.ok) {
                        const data = await response.json();
                        if (data.sessions && data.sessions.length > 0) {
                            // Leer desde localStorage para evitar leer estado antiguo (stale closure)
                            const savedSessionId = localStorage.getItem('mealfit_current_session');
                            const isCurrentValid = data.sessions.some(s => s.id === savedSessionId);
                            
                            if (!isCurrentValid) {
                                setCurrentSessionId(data.sessions[0].id);
                            } else if (currentSessionId !== savedSessionId) {
                                setCurrentSessionId(savedSessionId);
                            }
                        } else {
                            const newId = crypto.randomUUID();
                            setCurrentSessionId(newId);
                        }
                    }
                } catch (e) {
