        }, 2500);

        return () => clearInterval(intervalId);
    }, [chatSessions, fetchChatSessions, titlePollCount]);

    // Cargar historial de mensajes de forma segura (evitar 403 prematuro)
    useEffect(() => {
        // SIEMPRE esperar a que la sesi├│n de Supabase est├⌐ hidratada antes de hacer peticiones autenticadas
        if (!session?.user?.id) return;
        if (!currentSessionId) return;

        fetchSessionMessages(currentSessionId);
    }, [currentSessionId, fetchSessionMessages, session?.user?.id]);

    const handleNewChat = () => {
        const newId = crypto.randomUUID();
        setGuestSessionIds(prev => {
            const newList = [newId, ...prev].slice(0, 40);
            localStorage.setItem('mealfit_guest_sessions_list', JSON.stringify(newList));
            return newList;
        });
        setCurrentSessionId(newId);
        setMessages([{ role: 'model', content: '┬íHola! Soy tu agente conversacional de nutrici├│n IA. ┬┐En qu├⌐ te puedo ayudar hoy?', isWelcome: true }]);
        setInput('');
        clearSelectedFile();
        fetchChatSessions();
        if (window.innerWidth <= 768) {
            setShowSidebar(false);
