import { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useNavigate, Navigate, useLocation } from 'react-router-dom';
import { CheckCircle, Loader2 } from 'lucide-react';
import PropTypes from 'prop-types';

import { supabase } from '../supabase';
import { useAssessment } from '../context/AssessmentContext';
import { fetchWithAuth } from '../config/api';

// --- FUNCI├ôN HELPER: RETRY LOGIC ---
async function fetchWithRetry(url, options, retries = 3, backoff = 2000) {
    try {
        const response = await fetchWithAuth(url, options);
        if (response.status >= 500) throw new Error(`Server Error ${response.status}`);
        if (!response.ok) {
            const txt = await response.text();
            throw new Error(`Error ${response.status}: ${txt}`);
        }
        return response;
    } catch (err) {
        if (retries > 1) {
            console.warn(`ΓÜá∩╕Å Intento fallido. Reintentando en ${backoff / 1000}s... (${retries - 1} intentos restantes)`);
            await new Promise(r => setTimeout(r, backoff));
            return fetchWithRetry(url, options, retries - 1, backoff * 1.5);
        } else {
            throw err;
        }
    }
}

// --- GENERACI├ôN DE PLAN (CONEXI├ôN CON IA) ---
let globalGenerationPromise = null;

const generateAIPlan = async (formData) => {
    if (globalGenerationPromise) {
        console.warn("ΓÜá∩╕Å Reutilizando promesa de generaci├│n en curso (React StrictMode)...");
        return globalGenerationPromise;
    }

    const API_URL = '/api/analyze';


    globalGenerationPromise = (async () => {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 360000); // 6 minutos para permitir el bucle de revisi├│n m├⌐dica (Intento #2)

        try {
            const response = await fetchWithRetry(API_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(formData),
                signal: controller.signal
            }, 3);

            clearTimeout(timeoutId);
            const data = await response.json();

            return (Array.isArray(data) && data.length > 0) ? data[0] : data;
        } catch (error) {
            if (error.name === 'AbortError') {
                console.error("ΓÅ│ Error Fatal: Timeout total excedido.");
            } else {
                console.error("Γ¥î Fallaron todos los intentos de conexi├│n:", error);
            }
            console.warn("ΓÜá∩╕Å Activando Plan de Respaldo (Modo Offline)...");
            // Fallback plan b├ísico
            return {
                calories: 2000,
                macros: { protein: "150g", carbs: "200g", fats: "60g" },
                insights: [
                    "ΓÜá∩╕Å MODO OFFLINE: El servidor de IA no respondi├│.",
                    "Este es un plan generado localmente con 3 opciones para que no pierdas el ritmo."
                ],
                days: [
                    {
                        day: 1,
                        meals: [
                            { meal: "Desayuno", time: "8:00 AM", name: "Mang├║ con Huevo", desc: "Pur├⌐ de pl├ítano verde con huevo hervido.", cals: 450 },
                            { meal: "Almuerzo", time: "1:00 PM", name: "La Bandera (Versi├│n Fit)", desc: "Arroz, habichuelas y pollo guisado.", cals: 600 },
                            { meal: "Merienda", time: "4:00 PM", name: "Guineo Maduro", desc: "Una unidad mediana.", cals: 200 },
                            { meal: "Cena", time: "8:00 PM", name: "Pescado al Papillote", desc: "Filete de pescado con vegetales.", cals: 450 }
                        ]
                    },
                    {
                        day: 2,
                        meals: [
                            { meal: "Desayuno", time: "8:00 AM", name: "Avena con Frutas", desc: "Avena cocida con leche de almendras y frutas frescas.", cals: 400 },
                            { meal: "Almuerzo", time: "1:00 PM", name: "Pechuga a la Plancha", desc: "Pechuga macerada con lim├│n, acompa├▒ada de ensalada y batata.", cals: 550 },
                            { meal: "Merienda", time: "4:00 PM", name: "Yogur Griego", desc: "Yogur sin az├║car con nueces.", cals: 250 },
                            { meal: "Cena", time: "8:00 PM", name: "Ensalada de At├║n", desc: "At├║n en agua con lechuga, tomate y aguacate.", cals: 400 }
                        ]
                    },
                    {
                        day: 3,
                        meals: [
                            { meal: "Desayuno", time: "8:00 AM", name: "Huevos Revueltos con Espinaca", desc: "Huevos revueltos acompa├▒ados de espinaca y tostada integral.", cals: 380 },
                            { meal: "Almuerzo", time: "1:00 PM", name: "Sancocho Ligero", desc: "Sancocho con viandas y pollo, bajo en grasa.", cals: 650 },
                            { meal: "Merienda", time: "4:00 PM", name: "Manzana con Mantequilla de Man├¡", desc: "Rodajas de manzana fresca con una cucharada de mantequilla de man├¡.", cals: 250 },
                            { meal: "Cena", time: "8:00 PM", name: "Pollo Desmenuzado", desc: "Pechuga de pollo desmenuzada con pimientos y cebolla.", cals: 420 }
                        ]
                    }
                ],
                shoppingList: { daily: ["Pl├ítanos", "Huevos", "Pollo", "Vegetales Variados", "Arroz", "Habichuelas", "Avena", "Frutas", "At├║n", "Aguacate", "Batata"] }
            };
        } finally {
            globalGenerationPromise = null;
        }
    })();

    return globalGenerationPromise;
};

// --- GUARDAR PLAN EN HISTORIAL (SUPABASE) ---
const savePlanToHistory = async (finalPlan) => {
    if (!finalPlan || (!finalPlan.perfectDay && !finalPlan.meals && !finalPlan.days)) {
        console.warn("ΓÜá∩╕Å Intento de guardar un plan vac├¡o o inv├ílido.");
        return;
    }
    try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.user) {

            return;
        }

        const { data: recentPlans } = await supabase
            .from('meal_plans')
            .select('created_at')
            .eq('user_id', session.user.id)
            .order('created_at', { ascending: false })
            .limit(1);

        if (recentPlans && recentPlans.length > 0) {
            const diffSeconds = (Date.now() - new Date(recentPlans[0].created_at).getTime()) / 1000;
            if (diffSeconds < 60) {

                return;
            }
        }

        const calories = parseInt(finalPlan.calories || finalPlan.estimated_calories) || 0;
        const macros = finalPlan.macros || {};
        const dateOptions = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
        const planName = `Plan del ${new Date().toLocaleDateString('es-DO', dateOptions)}`;

        const { error: saveError } = await supabase.from('meal_plans').insert({
            user_id: session.user.id,
            plan_data: finalPlan,
            name: planName,
            calories: calories,
            macros: macros,
            created_at: new Date().toISOString()
        });

        if (saveError) {
            console.error("Γ¥î Error guardando historial:", saveError.message);
        } else {

        }
    } catch (dbError) {
        console.error("ΓÜá∩╕Å Error cr├¡tico al intentar guardar historial:", dbError);
    }
};

const Plan = () => {
    // 1. HOOKS
    const { formData, saveGeneratedPlan, setCurrentStep } = useAssessment();
    const [status, setStatus] = useState('analyzing');
    const [planData, setPlanData] = useState(null);
    const navigate = useNavigate();
    const location = useLocation();
    const previousMeals = location.state?.previousMeals || [];

    // 2. USEEFFECT
    useEffect(() => {
        // Validaci├│n de seguridad: Si no hay datos, no hacemos nada (el return de abajo redirige)
        if (!formData.age || !formData.mainGoal) return;

        // --- BLOQUEO DE DOBLE EJECUCI├ôN (INTENTO 2: Cleanup Flag) ---
        // Esto protege contra el "StrictMode" en desarrollo que monta/desmonta/monta r├ípido
        let ignore = false;

        window.scrollTo(0, 0);

        const processPlan = async () => {
            try {
                if (ignore) return;

                // FASE 1: UI de "Analizando"
                setStatus('analyzing');
                // Peque├▒a espera para que el usuario vea la animaci├│n de inicio
                await new Promise(r => setTimeout(r, 1500));

                if (ignore) return;

                // FASE 2: Llamada a la IA
                setStatus('generating');

                // --- INTEGRACI├ôN DE MEMORIA (SUPABASE) ---
                let userId = localStorage.getItem('mealfit_user_id');
                // IMPORTANTE: Evitar cadena "guest" literal que rompe UUID en Postgres
                if (userId === 'guest') userId = null;

                let guestSessionId = localStorage.getItem('mealfit_guest_session_id');
                if (!userId && !guestSessionId) {
                    guestSessionId = crypto.randomUUID();
                    localStorage.setItem('mealfit_guest_session_id', guestSessionId);
                }

                // AQU├ì EST├ü EL CAMBIO APLICADO: Agregamos session_id validos y previousMeals
                const dataToSend = {
                    ...formData,
                    user_id: userId, // Siempre es un UUID v├ílido o null
                    session_id: userId || guestSessionId, // Siempre es un UUID v├ílido
                    previous_meals: previousMeals
                };



                // Enviamos al backend (Nota: generateAIPlan YA NO inserta en DB autom├íticamente)
                const generatedPlan = await generateAIPlan(dataToSend);

                // SI EL COMPONENTE SE DESMONT├ô, DETENEMOS AQU├ì (NO GUARDAMOS EN DB)
                if (ignore) {

                    return;
                }

                // L├│gica de fechas para las compras (Grocery Cycle)
                const oldPlanStr = localStorage.getItem('mealfit_plan');
                const oldPlan = oldPlanStr ? JSON.parse(oldPlanStr) : {};
                
                if (previousMeals && previousMeals.length > 0) {
                    // Si estamos "Actualizando Platos" (men├║ rotativo), mantenemos la fecha original
                    generatedPlan.grocery_start_date = oldPlan.grocery_start_date || oldPlan.created_at || new Date().toISOString();
                } else {
                    // Si es un "Ciclo Renovado" (plan nuevo desde cero), empezamos a contar desde hoy
                    generatedPlan.grocery_start_date = new Date().toISOString();
                }

                // El backend ya guarda el plan en _save_plan_and_track_background (con t├¡tulo IA, frecuencias, etc.)
                // NO guardamos aqu├¡ para evitar duplicados en el historial.

                // Guardamos el resultado en el contexto global
                saveGeneratedPlan(generatedPlan);
                setPlanData(generatedPlan);

                // FASE 3: ├ëxito, llenado de barra al 100% y Redirecci├│n al Dashboard
                setStatus('ready');
                setTimeout(() => {
                    setCurrentStep(0);
                    navigate('/dashboard', { replace: true });
                }, 800);

            } catch (error) {
                console.error("Γ¥î Error generando el plan:", error);
                // En caso de error, podr├¡amos redirigir al dashboard con el plan offline (fallback)
                // O mostrar un error. Por ahora asumimos que el fallback del servicio funciona.
                if (!ignore) setStatus('ready');
            }
        };

        processPlan();

        // CLEANUP FUNCTION: Se ejecuta si el componente se desmonta
        return () => {
            ignore = true;
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    // 3. RENDERIZADO CONDICIONAL

    // Si el usuario intenta entrar directo sin llenar el formulario
    if (!formData.age || !formData.mainGoal) {
        return <Navigate to="/assessment" />;
    }

    // Pantalla de Carga (├║nica vista del componente mientras se genera)
    return <LoadingScreen status={status} />;
};

