const LoadingScreen = ({ status }) => {
    const [progress, setProgress] = useState(0);
    const [tipIndex, setTipIndex] = useState(0);

    const steps = [
        { text: "Conectando con servidor seguro", icon: "≡ƒöÉ", pct: 5 },
        { text: "Analizando tu metabolismo basal", icon: "≡ƒº¼", pct: 18 },
        { text: "Calculando distribuci├│n de macros", icon: "ΓÜí", pct: 35 },
        { text: "Seleccionando ingredientes locales", icon: "≡ƒÑæ", pct: 50 },
        { text: "Generando recetas personalizadas", icon: "≡ƒæ¿ΓÇì≡ƒì│", pct: 68 },
        { text: "Optimizando tu plan semanal", icon: "≡ƒôè", pct: 82 },
        { text: "Finalizando estrategia", icon: "Γ£¿", pct: 93 },
