    const tips = [
        "≡ƒÆí Beber agua antes de cada comida ayuda a controlar el apetito",
        "≡ƒÆí Las prote├¡nas aceleran tu metabolismo hasta un 30%",
        "≡ƒÆí Comer despacio mejora la digesti├│n y saciedad",
        "≡ƒÆí El sue├▒o es clave: sin ├⌐l, las hormonas del hambre se descontrolan",
        "≡ƒÆí Una comida balanceada tiene prote├¡na, carbohidrato y grasa saludable",
    ];

    useEffect(() => {
        if (status === 'ready') {
            setProgress(100);
            return;
        }

        // Intervalo de 500ms (2 actualizaciones por segundo)
        const timer = setInterval(() => {
            setProgress((old) => {
                if (old >= 99) return 99;
                
                // La generaci├│n toma ~60 a 67 segundos.
                // Escalamos los incrementos para que alcance el 95% en unos 60-65 segundos.
                let diff;
                if (old < 20) {
                    // 0 a 20%: Primeros ~5 segundos (avg 2% por tick)
                    diff = Math.random() * 2 + 1; // 1 a 3
                } else if (old < 50) {
                    // 20 a 50%: Siguientes ~15 segundos (avg 1% por tick)
                    diff = Math.random() * 1 + 0.5; // 0.5 a 1.5
                } else if (old < 80) {
                    // 50 a 80%: Siguientes ~25 segundos (avg 0.6% por tick)
                    diff = Math.random() * 0.8 + 0.2; // 0.2 a 1.0
                } else if (old < 95) {
                    // 80 a 95%: Siguientes ~20 segundos (avg 0.35% por tick)
                    diff = Math.random() * 0.5 + 0.1; // 0.1 a 0.6
                } else {
                    // 95 a 99%: S├║per lento si se demora m├ís de 65s (avg 0.12% por tick)
                    diff = Math.random() * 0.15 + 0.05; // 0.05 a 0.2
                }
                
                return Math.min(old + diff, 99);
            });
        }, 500);
        return () => clearInterval(timer);
    }, [status]);

    useEffect(() => {
        const tipTimer = setInterval(() => {
            setTipIndex((old) => (old + 1) % tips.length);
        }, 4500);
        return () => clearInterval(tipTimer);
    }, [tips.length]);

    // Determinar qu├⌐ pasos ya se completaron
