                <!-- TITLE & DESC -->
                <div style="margin-bottom: 30px;">
                    <h1 style="font-size: 26pt; font-weight: 900; color: #0F172A; margin: 0 0 10px 0; line-height: 1.2;">${meal.name}</h1>
